import { readFileSync } from 'node:fs';
const strategy = readFileSync('packages/agent-core/src/agent/compaction/strategy.ts', 'utf8');
const ladder = readFileSync('apps/liora/src/utils/usage/context-ladder.ts', 'utf8');
const sdk = readFileSync('packages/node-sdk/src/index.ts', 'utf8');
const fails = [];
if (!strategy.includes('export const DEFAULT_COMPACTION_TRIGGER_RATIO = 0.80')) fails.push('soft');
if (!strategy.includes('export const DEFAULT_COMPACTION_BLOCK_RATIO = 0.92')) fails.push('hard');
if (!strategy.includes('export const DEFAULT_ASYNC_COMPACTION_TRIGGER_RATIO = 0.70')) fails.push('async');
if (!strategy.includes('reservedContextSize: 50_000')) fails.push('reserved');
if (!strategy.includes('absoluteTriggerTokens: 200_000')) fails.push('absolute');
if (!strategy.includes('maxRecentMessages: 4')) fails.push('maxRecent');
if (!strategy.includes('assertCompactionLadderSafety(DEFAULT_COMPACTION_CONFIG')) fails.push('assert');
if (!ladder.includes("from '@superliora/sdk'")) fails.push('ladder-sdk');
if (!ladder.includes('DEFAULT_COMPACTION_TRIGGER_RATIO')) fails.push('ladder-soft');
if (!sdk.includes('DEFAULT_COMPACTION_TRIGGER_RATIO')) fails.push('sdk-export');
if (fails.length) { console.error(fails.join(',')); process.exit(1); }
console.log('research-aligned-ladder-ok');

import { readFileSync } from 'node:fs';
const strategy = readFileSync('packages/agent-core/src/agent/compaction/strategy.ts', 'utf8');
const densifySoft = /DEFAULT_COMPACTION_TRIGGER_RATIO\s*=\s*0\.0[0-4]/;
const densifyAsync = /DEFAULT_ASYNC_COMPACTION_TRIGGER_RATIO\s*=\s*0\.0[0-4]/;
if (densifySoft.test(strategy) || densifyAsync.test(strategy)) {
  console.error('densify-soft-or-async-detected');
  process.exit(1);
}
console.log('no-densify-soft-async');
